import{_ as e,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"27. Orientation On Appointment","description":"","frontmatter":{"title":"27. Orientation On Appointment","eba":"Doctors in Training 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/27-orientation-on-appointment.md","filePath":"ebas/doctors-in-training/doctor-employment/27-orientation-on-appointment.md"}'),i={name:"ebas/doctors-in-training/doctor-employment/27-orientation-on-appointment.md"};function r(s,t,c,p,l,d){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="_27-orientation-on-appointment" tabindex="-1">27. Orientation On Appointment <a class="header-anchor" href="#_27-orientation-on-appointment" aria-label="Permalink to &quot;27. Orientation On Appointment&quot;">​</a></h1><p><strong>27.1</strong> On a Doctor’s appointment to a new position or a new location (including a Rotation) and as an orientation, the Health Service must</p><p><strong>(a)</strong> direct the Doctor to where they can locate a copy of this Agreement; and</p><p><strong>(b)</strong> inform the Doctor of those matters that are essential to the safe and efficient discharge of their responsibilities. This will include a statement from a person authorised by the Health Service that to support safe working hours, Doctors must as far as is practicable, submit time worked on a timesheet (or equivalent) within the time required by the Health Service, this includes un-rostered overtime that is not approved in advance.</p><p><strong>27.2</strong> The orientation information must include a “Unit Handbook” or similar document containing current, written information that covers the following:</p><p><strong>(a)</strong> job duties, responsibilities and authority;</p><p><strong>(b)</strong> emergency procedures;</p><p><strong>(c)</strong> relevant clinical, ward and quality procedures, including contact details;</p><p><strong>(d)</strong> procedures for ordering supplies and medical tests;</p><p><strong>(e)</strong> information about Training Time arrangements consistent with <a href="/eba/ebas/doctors-in-training/hours-of-work/34-training-time.html">clause 34</a>;</p><p><strong>(f)</strong> a copy of the bullying policy and/or procedure that is consistent with the language in <a href="/eba/ebas/doctors-in-training/consultation-disputes/14-prevention-and-management-of-workplace-bullying.html">clause 14</a> which promotes the statement &quot;Bullying will not be tolerated in the workplace&quot;;</p><p><strong>(g)</strong> a copy of the Authorised Un-rostered Overtime Protocol consistent with <a href="/eba/ebas/doctors-in-training/hours-of-work/36-overtime.html">clause 36.3</a>;</p><p><strong>(h)</strong> reference to <a href="/eba/ebas/doctors-in-training/leave/59-replacement-of-doctors-when-on-leave.html">clause 59</a> Replacement of Doctors when on leave, and <a href="/eba/ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.html">clause 41</a> Workload Management and Review;</p><p><strong>(i)</strong> a Performance Management Protocol consistent with <a href="/eba/ebas/doctors-in-training/consultation-disputes/13-managing-conduct-and-performance-discipline.html">clause 13</a>;</p><p><strong>(j)</strong> specific reference to <a href="/eba/ebas/doctors-in-training/allowances/56-uniform-laundry-allowance.html">clause 56</a> and whether the Doctor will be:</p><p><strong>(i)</strong> supplied with sufficient suitable and serviceable uniforms (e.g. scrubs) laundered at the expense of the Health Service; and</p><p><strong>(ii)</strong> paid the Uniform/Laundry allowance; and</p><p><strong>(k)</strong> a copy of the Clinical Escalation Pathway (however titled or styled).</p><p><strong>27.3</strong> During a Rotation, the orientation described in subclause 27.1 is the responsibility of the Rotation Hospital. Doctors are responsible for ensuring that they request appropriate information and clarification when required.</p><p>Plain language terms: orientation.</p>',20)])])}const g=e(i,[["render",r]]);export{m as __pageData,g as default};
